            ['id' => 'leistungen', 'h2' => 'Was beinhaltet Website-Wartung?', 'html' => '<ul><li>Hosting und Serverbetrieb</li><li>SSL-Zertifikat und HTTPS</li><li>Updates und technische Pflege</li><li>regelmäßige Backups</li><li>Sicherheitsprüfung und Wiederherstellung</li><li>Monitoring von Erreichbarkeit und Fehlern</li><li>kleinere Inhaltsänderungen je nach Paket</li></ul><p>Bei Sartu ist das im <a href="leistung-wartung.php">Rundum-Schutz</a> gebündelt.</p>'],
            ['id' => 'backups', 'h2' => 'Wie oft sollten Backups erstellt werden?', 'html' => '<p>Für Unternehmenswebsites sind tägliche Backups sinnvoll. Noch wichtiger ist, dass Backups extern gespeichert und im Ernstfall schnell wiederhergestellt werden können.</p><p>Ein Backup ist nur dann wertvoll, wenn klar ist, welcher Stand wiederhergestellt wird und wer im Notfall reagiert.</p>'],
            ['id' => 'dsgvo', 'h2' => 'Ist Hosting in Deutschland für DSGVO wichtig?', 'html' => '<p>Hosting in Deutschland oder der EU kann die DSGVO-konforme Verarbeitung vereinfachen. Entscheidend sind außerdem Auftragsverarbeitung, SSL, Datenschutzerklärung, Cookie-/Tracking-Einstellungen und ein sicherer Umgang mit Formularanfragen.</p><p>Wer personenbezogene Daten über Kontaktformulare verarbeitet, sollte Sicherheit und Datenschutz nicht als Nebensache behandeln.</p>'],
            ['id' => 'ausfall', 'h2' => 'Was passiert, wenn eine Website ausfällt oder gehackt wird?', 'html' => '<p>Dann zählt ein klarer Plan: Website prüfen, Sicherheitslücke schließen, sauberes Backup einspielen, Passwörter ändern, Formulare und Daten prüfen und die Seite wieder erreichbar machen.</p><p>Gute Wartung verhindert nicht jedes Problem, verkürzt aber Ausfallzeiten und reduziert das Risiko deutlich.</p>'],
        ],
        'faqs' => [
            ['q' => 'Braucht jede Website Wartung?', 'a' => 'Ja. Jede geschäftliche Website sollte technisch aktuell, sicher, gesichert und erreichbar bleiben. Ohne Wartung steigen Sicherheits- und Ausfallrisiken.'],
            ['q' => 'Kann ich Hosting und Wartung trennen?', 'a' => 'Ja, technisch ist das möglich. Praktisch ist eine gemeinsame Betreuung oft einfacher, weil Server, Updates, Backups und Support zusammenpassen.'],
            ['q' => 'Was ist ein SSL-Zertifikat?', 'a' => 'Ein SSL-Zertifikat verschlüsselt die Verbindung zwischen Website und Besucher. Es ist Standard für Vertrauen, Datenschutz und sichere Formulare.'],
            ['q' => 'Wie schnell sollte eine Website laden?', 'a' => 'Mobil sollte eine Website möglichst in wenigen Sekunden nutzbar sein. Schnelle Ladezeiten verbessern Nutzererlebnis, Anfragen und Suchmaschinenbewertung.'],
        ],
    ],
    'ratgeber-website-texte' => [
        'title' => 'Website-Texte schreiben: SEO, Struktur & Kundenansprache | Sartu',
        'description' => 'Website-Texte schreiben lassen oder selbst schreiben: SEO-Texte, Startseite, Leistungsseiten, Keywords, Tonalität, Länge und klare Kundenansprache.',
        'h1' => 'Website-Texte schreiben:',
        'accent' => 'verständlich, verkaufsstark und SEO-tauglich.',
        'lead' => 'Dieser Ratgeber zeigt, welche Texte eine Website braucht, wie SEO-Texte funktionieren und wie Fachsprache verständlich wird, ohne wichtige Suchbegriffe zu verlieren.',
        'answer' => 'Gute Website-Texte beantworten echte Kundenfragen, erklären Nutzen verständlich, verwenden relevante Keywords natürlich und führen Besucher zur nächsten sinnvollen Handlung.',
        'story_label' => 'Wenn Sie wissen, was Sie tun, aber nicht wie Sie es sagen sollen',
        'story' => 'Viele Unternehmen können ihre Leistung gut erklären, sobald sie mit Kunden sprechen. Auf der Website klingt es dann aber oft zu technisch, zu allgemein oder zu dünn für Google.',
        'toc' => [
            ['id' => 'seo-text', 'label' => 'SEO-Text'],
            ['id' => 'seiten', 'label' => 'Welche Texte?'],
            ['id' => 'keywords', 'label' => 'Keywords'],
            ['id' => 'ton', 'label' => 'Tonfall'],
            ['id' => 'ki', 'label' => 'KI-Texte'],
        ],
        'sections' => [
            ['id' => 'seo-text', 'h2' => 'Was ist ein guter SEO-Text?', 'html' => '<p>Ein guter SEO-Text ist kein Keyword-Teppich. Er beantwortet eine konkrete Suchintention besser als andere Seiten, ist logisch gegliedert und bleibt für Menschen leicht verständlich.</p><p>Wichtig sind klare Überschriften, konkrete Beispiele, natürliche Suchbegriffe, interne Links und Antworten auf typische Einwände. Genau diese Verbindung hilft Suchmaschinen und Besuchern.</p>'],
            ['id' => 'seiten', 'h2' => 'Welche Texte braucht eine Firmenwebsite?', 'html' => '<ul><li><strong>Startseite:</strong> Positionierung, Nutzen, wichtigste Leistungen, Vertrauen und Kontaktweg.</li><li><strong>Leistungsseiten:</strong> Problem, Lösung, Ablauf, Preise oder Preisrahmen, FAQ und Handlungsaufforderung.</li><li><strong>Über-uns-Seite:</strong> Vertrauen, Haltung, Arbeitsweise und Zielgruppe.</li><li><strong>Kontaktseite:</strong> niedrige Hürde, klare Erwartungen und einfache Anfrage.</li><li><strong>Ratgeber:</strong> ausführliche Antworten auf große Suchfragen.</li></ul>'],
            ['id' => 'keywords', 'h2' => 'Wie findet man die richtigen Keywords für Website-Texte?', 'html' => '<p>Starten Sie bei echten Kundenfragen: Was wird gesucht, bevor jemand anfragt? Welche Begriffe nutzt die Zielgruppe? Welche Region ist wichtig? Welche Einwände tauchen immer wieder auf?</p><p>Ein gutes Keyword ist nicht nur oft gesucht, sondern passt zur Leistung und zur Absicht des Suchenden. „Kosten“, „Dauer“, „Vergleich“, „in der Nähe“ und „Checkliste“ sind häufig starke Suchmuster.</p>'],
            ['id' => 'ton', 'h2' => 'Wie viel Fachsprache ist sinnvoll?', 'html' => '<p>Fachsprache ist gut, wenn sie Vertrauen schafft und ein Suchbegriff ist. Sie wird problematisch, wenn Kunden nicht verstehen, was gemeint ist. Die beste Lösung ist: Fachbegriff nennen und direkt verständlich erklären.</p><p>Beispiel: „OnPage-SEO“ kann stehen bleiben, wenn danach klar erklärt wird, dass es um Texte, Überschriften, interne Links und Seitenstruktur geht.</p>'],
            ['id' => 'ki', 'h2' => 'Kann KI Website-Texte schreiben?', 'html' => '<p>KI kann helfen, Themen zu sortieren, Varianten zu formulieren und Entwürfe zu beschleunigen. Gute Website-Texte brauchen trotzdem echte Informationen, Zielgruppenverständnis, fachliche Prüfung und redaktionelle Überarbeitung.</p><p>Wer KI-Texte ungeprüft übernimmt, bekommt oft allgemeine Aussagen. Stark werden Texte erst durch konkrete Leistung, Kundenschmerz, Beispiele, regionale Signale und klare Entscheidungshilfen.</p><p>Mehr zur Umsetzung finden Sie unter <a href="leistung-texte.php">Website-Texte schreiben lassen</a>.</p>'],
        ],
        'faqs' => [
            ['q' => 'Wie lang sollte ein Website-Text sein?', 'a' => 'So lang wie nötig, um Suchintention, Nutzen, Ablauf, Vertrauen und Einwände zu beantworten. Es gibt keine feste Wortzahl, die immer richtig ist.'],
            ['q' => 'Sollte jede Leistung eine eigene Seite haben?', 'a' => 'Ja, wenn die Leistung einzeln bei Google gefunden werden soll. Eine eigene Seite kann gezielter auf Suchintention und Fragen eingehen.'],
            ['q' => 'Muss ich Keywords selbst liefern?', 'a' => 'Nein. Hilfreich sind aber Leistungen, Orte, Zielgruppen und typische Kundenfragen. Daraus lassen sich passende Keywords ableiten.'],
            ['q' => 'Sind kurze Texte besser als lange Texte?', 'a' => 'Kurze Texte sind gut, wenn sie vollständig antworten. Bei erklärungsbedürftigen Leistungen sind längere Seiten oft besser, weil sie mehr Fragen und Einwände klären.'],
