        'sections' => [
            ['id' => 'motive', 'h2' => 'Welche Bilder braucht eine Firmenwebsite?', 'html' => '<p>Die besten Website-Bilder beantworten stille Besucherfragen: Wer steckt dahinter? Wie sieht die Arbeit aus? Ist das Unternehmen echt? Passt die Leistung zu meinem Problem?</p><ul><li><strong>Team oder Ansprechpartner:</strong> schafft Vertrauen und senkt die Kontakthürde.</li><li><strong>Standort oder Arbeitsplatz:</strong> macht das Unternehmen greifbar.</li><li><strong>Leistungssituationen:</strong> zeigen, wie gearbeitet wird.</li><li><strong>Details und Materialien:</strong> wirken hochwertig und konkret.</li><li><strong>Vorher-nachher oder Ergebnisse:</strong> nur verwenden, wenn sie echt und belegbar sind.</li></ul>'],
            ['id' => 'qualitaet', 'h2' => 'Reichen Smartphone-Fotos oder braucht man einen Fotografen?', 'html' => '<p>Gute Smartphone-Fotos können für den Start reichen, wenn Licht, Bildausschnitt und Schärfe stimmen. Für Hero-Bereiche, Teamfotos und wichtige Vertrauenselemente lohnt sich oft ein professionelles Shooting.</p><p>Entscheidend ist nicht nur die Kamera, sondern die Wirkung: Bilder sollten hell, ruhig, realistisch und zur Marke passend sein. Unnatürliche KI-Optik oder generische Stockfotos können schnell weniger vertrauenswürdig wirken.</p>'],
            ['id' => 'seo', 'h2' => 'Wie werden Website-Bilder für SEO und Ladezeit optimiert?', 'html' => '<p>Bilder sollten komprimiert, richtig zugeschnitten und in modernen Formaten wie WebP bereitgestellt werden. Zu große Dateien verlangsamen die Website und verschlechtern die mobile Erfahrung.</p><p>Für SEO helfen sprechende Dateinamen und Alt-Texte. Ein guter Alt-Text beschreibt sachlich, was zu sehen ist, und nutzt wichtige Begriffe nur dann, wenn sie wirklich passen.</p>'],
            ['id' => 'rechte', 'h2' => 'Worauf muss man bei Bildrechten achten?', 'html' => '<p>Für jedes Bild muss klar sein, ob es auf der Website verwendet werden darf. Das gilt für Fotografenbilder, Stockmaterial, KI-Bilder, Kundenprojekte und Fotos mit Personen.</p><p>Wenn Mitarbeitende, Kunden oder Räume erkennbar sind, sollten Einwilligungen und Nutzungsumfang sauber geklärt werden. Bei Stockbildern zählen Lizenzbedingungen, Bearbeitungsrechte und erlaubte Einsatzbereiche.</p>'],
            ['id' => 'checkliste', 'h2' => 'Checkliste: Bilder für die Website vorbereiten', 'html' => '<ul><li>5 bis 10 gute Bilder für Startseite und wichtige Leistungsseiten sammeln.</li><li>Team, Standort, Arbeitssituationen und Details abdecken.</li><li>Unklare Bildrechte vor Veröffentlichung prüfen.</li><li>Hero-Bilder im Querformat und mit ruhiger Fläche für Text planen.</li><li>Bilddateien komprimieren und sinnvoll benennen.</li><li>Alt-Texte sachlich und hilfreich schreiben.</li><li>Platzhalter klar als Platzhalter behandeln und später ersetzen.</li></ul><p>Wenn noch keine echten Fotos vorhanden sind, kann eine Website trotzdem starten. Wichtig ist, keine künstlichen Referenzen, Bewertungen oder Ergebnisse zu erfinden.</p>'],
