        'faqs' => [
            ['q' => 'Welche Bilder braucht eine Firmenwebsite?', 'a' => 'Sinnvoll sind Bilder von Ansprechpartnern, Team, Standort, Arbeitssituationen, Details der Leistung und echten Ergebnissen, sofern diese rechtlich verwendet werden dürfen.'],
            ['q' => 'Kann man mit Platzhalter-Fotos starten?', 'a' => 'Ja, wenn Platzhalter ehrlich genutzt und später ersetzt werden. Sie sollten professionell wirken, aber keine falschen Referenzen, Kunden oder Ergebnisse vortäuschen.'],
            ['q' => 'Sind KI-Bilder für Websites sinnvoll?', 'a' => 'KI-Bilder können für neutrale Stimmungen oder Platzhalter helfen. Für Vertrauen, Team, Standort und echte Arbeit sind reale Fotos meist stärker.'],
            ['q' => 'Wie wichtig sind Alt-Texte für Bilder?', 'a' => 'Alt-Texte helfen Suchmaschinen und Screenreadern zu verstehen, was auf einem Bild zu sehen ist. Sie sollten kurz, beschreibend und natürlich formuliert sein.'],
